INSERT INTO public.email_templates (template_key, name, subject, description, html_body, is_active) VALUES

('auth_welcome','Welcome Email','Welcome to NanoCircuit! 🎉','Welcome email sent to new customers on registration','<!DOCTYPE html><html><head><meta charset="UTF-8"><style>body{font-family:Arial,sans-serif;background:#f5f5f5;margin:0;padding:20px}.c{max-width:600px;margin:0 auto;background:#fff;border-radius:8px;overflow:hidden}.logo{background:#1a1a2e;padding:18px 32px;text-align:center}.logo img{max-height:44px;width:auto}.h{background:#1a1a2e;color:#fff;padding:24px 32px;text-align:center}.h h1{margin:0;font-size:22px}.b{padding:24px 32px;color:#333}.features{display:flex;flex-direction:column;gap:10px;margin:20px 0}.feat{background:#f9f9f9;border-radius:6px;padding:12px 16px;font-size:14px}.cta{text-align:center;margin:24px 0}.cta a{background:#1a1a2e;color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-size:14px;font-weight:bold}.f{background:#f0f0f0;padding:16px 32px;text-align:center;font-size:12px;color:#888}</style></head><body><div class="c"><div class="logo"><img src="https://rcefmfiqqqsfurkdljup.supabase.co/storage/v1/object/public/images/site-logo.svg" alt="NanoCircuit" style="max-height:80px;max-width:280px;width:auto;filter:brightness(0) invert(1)"></div><div class="h"><h1>🎉 Welcome to NanoCircuit!</h1></div><div class="b"><p>Hi {{customer_name}}, welcome aboard! Your account has been created successfully.</p><div class="features"><div class="feat">🛒 Shop thousands of electronics components</div><div class="feat">🔌 Order custom PCB manufacturing</div><div class="feat">📦 Pre-order hard-to-find parts</div></div><div class="cta"><a href="https://nanocircuit.lk">Start Shopping</a></div></div><div class="f">NanoCircuit.lk &mdash; nanocircuit.lk</div></div></body></html>',false),

('order_placed','Order Placed','Your order #{{order_id}} has been received','Sent to customer when a new order is placed','<!DOCTYPE html><html><head><meta charset="UTF-8"><style>body{font-family:Arial,sans-serif;background:#f5f5f5;margin:0;padding:20px}.c{max-width:600px;margin:0 auto;background:#fff;border-radius:8px;overflow:hidden}.logo{background:#1a1a2e;padding:18px 32px;text-align:center}.logo img{max-height:44px;width:auto}.h{background:#1a1a2e;color:#fff;padding:24px 32px}.h h1{margin:0;font-size:20px}.b{padding:24px 32px;color:#333}.badge{display:inline-block;background:#e8f5e9;color:#2e7d32;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;margin-bottom:16px}.row{display:flex;justify-content:space-between;background:#f9f9f9;border-radius:6px;padding:12px 16px;margin-bottom:10px;font-size:14px}.label{color:#888;font-size:12px}.val{font-weight:bold;color:#1a1a2e}.cta{text-align:center;margin:24px 0}.cta a{background:#1a1a2e;color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-size:14px;font-weight:bold}.f{background:#f0f0f0;padding:16px 32px;text-align:center;font-size:12px;color:#888}</style></head><body><div class="c"><div class="logo"><img src="https://rcefmfiqqqsfurkdljup.supabase.co/storage/v1/object/public/images/site-logo.svg" alt="NanoCircuit" style="max-height:80px;max-width:280px;width:auto;filter:brightness(0) invert(1)"></div><div class="h"><h1>✅ Order Received</h1></div><div class="b"><div class="badge">Order #{{order_id}}</div><p>Hi {{customer_name}}, thank you for your order! We have received your order and it is being processed.</p><div class="row"><span><div class="label">Order Total</div><div class="val">Rs. {{total}}</div></span><span><div class="label">Payment</div><div class="val">{{payment_method}}</div></span></div><div class="cta"><a href="https://nanocircuit.lk/profile">Track Your Order</a></div></div><div class="f">NanoCircuit.lk &mdash; nanocircuit.lk</div></div></body></html>',false),

